        const selection = editor.selection;

        editor.edit(editBuilder => {
            // Get the selected lines
            const startLine = selection.start.line;
            const endLine = selection.end.line;

            let commentedLines = new Set<number>();

            // First pass: determine which lines are commented
            for (let i = startLine; i <= endLine; i++) {
                const line = document.lineAt(i);
                if (line.text.trimStart().startsWith('#')) {
                    commentedLines.add(i);
                }
            }

            // Second pass: toggle comments in alternating pattern
            let shouldComment = commentedLines.size === 0;
            for (let i = startLine; i <= endLine; i++) {
                const line = document.lineAt(i);
                const lineText = line.text;

                if (shouldComment && !commentedLines.has(i)) {
                    // Add comment
                    editBuilder.insert(new vscode.Position(i, 0), '# ');
                } else if (!shouldComment && commentedLines.has(i)) {
                    // Remove comment
                    const commentStart = lineText.indexOf('#');
                    editBuilder.delete(new vscode.Range(
                        new vscode.Position(i, commentStart),
                        new vscode.Position(i, commentStart + 2)
                    ));
                }
                shouldComment = !shouldComment;
            }
        });
    });

    context.subscriptions.push(disposable);
}
```

