```python
from typing import Literal, Union
from pydantic import BaseModel, model_validator

class MessageContainer(BaseModel):
    type: Literal["message"]
    # ... other fields

class ViewContainer(BaseModel):
    type: Literal["view"]
    # ... other fields

class ActionsBase(BaseModel):
    type: Literal["block_actions"]

class MessageActions(ActionsBase):
    container: MessageContainer
    # ... other fields

class ViewActions(ActionsBase):
    container: ViewContainer
    # ... other fields

class ViewSubmission(BaseModel):
    type: Literal["view_submission"]
    # ... other fields

class SlackInteraction(BaseModel):
    type: Literal["block_actions", "view_submission"]
    container: Union[MessageContainer, ViewContainer] | None = None

    @model_validator(mode='before')
    @classmethod
    def validate_structure(cls, data: dict) -> dict:
        if not isinstance(data, dict):
            raise ValueError("Data must be a dictionary")

        interaction_type = data.get('type')

        if interaction_type == "block_actions":
            container = data.get('container', {})
            container_type = container.get('type')

            if container_type == "message":
                return MessageActions(**data)
            elif container_type == "view":
                return ViewActions(**data)
            else:
                raise ValueError(f"Invalid container type: {container_type}")

        elif interaction_type == "view_submission":
            return ViewSubmission(**data)
        else:
            raise ValueError(f"Invalid interaction type: {interaction_type}")

