from typing import Callable

@dataclass
class Parent:
    name: str
    child: Child

@dataclass
class Child:
    parent_factory: Callable[[], Parent]

    @property
    def parent(self) -> Parent:
        return self.parent_factory()

# Usage
def create_parent_child(name: str) -> Parent:
    parent = Parent(name=name, child=Child(lambda: parent))
    return parent

parent = create_parent_child("foo")
```

3. Using `default_factory` with a late binding:
```python
from __future__ import annotations
from dataclasses import dataclass, field
from typing import Any

@dataclass
class Parent:
    name: str
    child: Child

    def __post_init__(self) -> None:
        self.child._parent = self

@dataclass
class Child:
    _parent: Parent = field(init=False)

    def __init__(self) -> None:
        pass

    @property
    def parent(self) -> Parent:
        return self._parent

# Usage
child = Child()
parent = Parent(name="foo", child=child)
```

4. Using a weakref to avoid circular references:
```python
from __future__ import annotations
from dataclasses import dataclass
import weakref
from typing import Any

@dataclass
class Parent:
    name: str
    child: Child

    def __post_init__(self) -> None:
        self.child._parent = weakref.ref(self)

@dataclass
class Child:
    _parent: Any = field(init=False)  # Type is actually weakref.ref[Parent]

    def __init__(self) -> None:
        pass

    @property
    def parent(self) -> Parent:
        return self._parent()

# Usage
