I understand you're trying to work with two different AWS accounts simultaneously in your Python application - one for Secret Manager and another for Athena queries. Let me help you with a better approach to handle this scenario.

Here's a more robust solution that allows you to maintain separate sessions for different AWS accounts:

```python
import boto3
from botocore.exceptions import ClientError

class AWSAuthenticator:
    def __init__(self, region):
        self.region = region
        self.sessions = {}
        self.clients = {}

    def get_session(self, profile_name):
        """Get or create a session for a specific profile"""
        if profile_name not in self.sessions:
            try:
                self.sessions[profile_name] = boto3.Session(
                    profile_name=profile_name,
                    region_name=self.region
                )
            except Exception as e:
                raise Exception(f"Failed to create session for profile {profile_name}: {str(e)}")
        return self.sessions[profile_name]

    def get_client(self, profile_name, service):
        """Get or create a client for a specific profile and service"""
        client_key = f"{profile_name}_{service}"
        if client_key not in self.clients:
            session = self.get_session(profile_name)
            try:
                self.clients[client_key] = session.client(service)
            except Exception as e:
                raise Exception(f"Failed to create {service} client for profile {profile_name}: {str(e)}")
        return self.clients[client_key]

    def get_secret(self, secret_name, profile_name):
        """Get secret from AWS Secrets Manager"""
        secrets_client = self.get_client(profile_name, 'secretsmanager')
        try:
            response = secrets_client.get_secret_value(SecretId=secret_name)
            return response['SecretString']
        except ClientError as e:
            raise Exception(f"Failed to get secret {secret_name}: {str(e)}")

    def query_athena(self, query, database, profile_name):
        """Execute Athena query"""
        athena_client = self.get_client(profile_name, 'athena')
        try:
            response = athena_client.start_query_execution(
                QueryString=query,
                QueryExecutionContext={'Database': database}
            )
            return response['QueryExecutionId']
        except ClientError as e:
            raise Exception(f"Failed to execute Athena query: {str(e)}")
```

Usage example:

```python
